<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Add') }} {{ $t('Priority') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    data(){
        return{
            isLoading:false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [               
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",                                                
                            label: this.$t('PriorityName'),
                            name: "PriorityName",
                            value: "",                            
                            placeholder: this.$t('Select Priority'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",                                                
                            label: this.$t('Status'),
                            name: "Tag",
                            value: "1001", 
                            config: {
                                options: [{value:1001,name:'Active'},{value:1002,name:'Inactive'}]
                            },                           
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "SelectField",                                                
                            label: this.$t('Dislpay Order'),
                            name: "DislpayOrder",
                            value: "", 
                            config: {
                                options: []
                            },                           
                            placeholder: this.$t('Select Dislpay Order'),
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "ColorField",
                            label: this.$t('Color Code'),
                            name: "Color Code",
                            value: "",
                            placeholder: "",
                            validationRules: {
                                "required": true
                            },
                            disabled: false,
                        } 
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows:5
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }
    },
    created:function(){        
        this.GetPriorityDisplayOrder();
    },
    methods:{
        GetPriorityDisplayOrder:function(){
            var ths=this;
            var url = `id=&moduleName=PROJECT&type=DISPLAY_ORDER_PRIORITY&search=&refId=`;
            DataService.GetDDLData(url).then((response)=>{                
                if (response.data && response.data.DATA) {
                    response.data.DATA.forEach((item)=>{                        
                        let obj={
                            name:item.name,
                            value:item.value
                        }                        
                        ths.FormSchema[0].Data[2].config.options.push(obj);
                    })
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            })
        },
        OnSubmit:function(){ 
            debugger           
            var ths=this;
            var url=`PriorityName=${ths.FormSchema[0].Data[0].value}&PriorityDescription=${ths.FormSchema[1].Data[0].value}&StatusId=${ths.FormSchema[0].Data[1].value}&displayOrder=${ths.FormSchema[0].Data[2].value}&colorCode=${encodeURIComponent(ths.FormSchema[0].Data[3].value)}`;
            DataService.SavePriority(url).then((response)=>{                
                if(response.data.result.length>0){
                    if(response.data.result[0].VALUE=='INSERT'){                        
                        ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('Priority')]), "success", true,  ths.$t("Alert")); 
                        var param = "id=&moduleName=PROJECT&type=PRIORITY";               
                        DataService.GetDDLData(param).then(function (response1) {                            
                            var json = [];
                            if (response1.data != null) {
                                json = response1.data.DATA;
                            }
                            ths.$emit('updatedata','priority_id', json); 
                            ths.Close();                         
                        });
                    }
                }
            });
        },
        Close:function(){
            this.$parent.isPriority=false
        }
    }
}
</script>